const input = $input.first().json;

const requiredText = (fieldName) => {
  const value = String(input[fieldName] ?? '').trim();
  if (!value) {
    throw new Error(`${fieldName} is required`);
  }
  return value;
};

const optionalText = (fieldName) => {
  const value = String(input[fieldName] ?? '').trim();
  return value || undefined;
};

const splitLinesOrCsv = (value) => {
  if (value === undefined || value === null) {
    return undefined;
  }
  const text = String(value)
    .split(/\r?\n|,/)
    .map((entry) => entry.trim())
    .filter(Boolean);
  return text.length > 0 ? text : undefined;
};

const baseUrl = requiredText('base_url').replace(/\/$/, '');
const requestBody = {
  project_key: requiredText('project_key'),
  task_text: requiredText('task_text'),
  project_profile: requiredText('project_profile'),
  workflow_id: requiredText('workflow_id'),
  milestone: requiredText('milestone'),
  priority_class: requiredText('priority_class'),
};

const optionalScalarFields = [
  'instruction_profile',
  'source',
  'thread_label',
  'artifact_root',
  'workspace_root',
];
for (const fieldName of optionalScalarFields) {
  const value = optionalText(fieldName);
  if (value !== undefined) {
    requestBody[fieldName] = value;
  }
}

const instructionOverlays = splitLinesOrCsv(input.instruction_overlays);
if (instructionOverlays !== undefined) {
  requestBody.instruction_overlays = instructionOverlays;
}

const constraints = splitLinesOrCsv(input.constraints);
if (constraints !== undefined) {
  requestBody.constraints = constraints;
}

const expectedOutput = splitLinesOrCsv(input.expected_output);
if (expectedOutput !== undefined) {
  requestBody.expected_output = expectedOutput;
}

return [
  {
    json: {
      base_url: baseUrl,
      request_body: requestBody,
    },
  },
];

const response = $input.first().json;
const submittedTask = response.data?.submitted_task;
const run = submittedTask?.run_details?.run ?? {};
const queueItem = run.queue_item ?? {};

return [
  {
    json: {
      ok: response.ok,
      request_id: response.request_id,
      run_id: run.id ?? null,
      flow_id: run.flow_id ?? null,
      queue_item_id: queueItem.id ?? null,
      queue_status: queueItem.status ?? null,
      run_status: run.status ?? null,
      project_key: submittedTask?.request?.project_key ?? null,
      workflow_id: submittedTask?.request?.workflow_id ?? null,
      milestone: submittedTask?.request?.milestone ?? null,
      submitted_at: submittedTask?.submitted_at ?? null,
      runtime_context: submittedTask?.runtime_context ?? null,
      raw_response: response,
    },
  },
];
